   138→    
   139→    async function loadJobs() {
   140→      try {
   141→        const data = await apiCall('/jobs');
   142→        const grid = document.getElementById('job-grid');
   143→        const emptyState = document.getElementById('empty-state');
   144→        
   145→        if (!data || data.jobs.length === 0) {
   146→          grid.style.display = 'none';
   147→          emptyState.style.display = 'block';
   148→          return;
   149→        }
   150→        
   151→        grid.innerHTML = data.jobs.map(job => `
   152→          <div class="job-card">
   153→            <div class="job-header">
   154→              <h3>${job.title}</h3>
   155→              <span class="job-type">${job.job_type || 'Full-time'}</span>
   156→            </div>
   157→            <div class="job-company">${job.company || job.poster_company || 'Company'}</div>
   158→            ${job.location ? `<div class="job-location">📍 ${job.location}</div>` : ''}
   159→            ${job.salary_range ? `<div class="job-salary">💰 ${job.salary_range}</div>` : ''}
   160→            ${job.description ? `<p class="job-desc">${job.description.substring(0, 150)}${job.description.length > 150 ? '...' : ''}</p>` : ''}
   161→            <div class="job-actions">
   162→              <a href="/interview.html?job_id=${job.id}&job_title=${encodeURIComponent(job.title)}&job_desc=${encodeURIComponent(job.description || '')}" class="btn btn-primary btn-sm">
   163→                Practice Interview
   164→              </a>
   165→            </div>
   166→          </div>
   167→        `).join('');
   168→        
   169→      } catch (err) {
   170→        console.error('Failed to load jobs:', err);
   171→      }
   172→    }
