   182→    function setupPostForm() {
   183→      document.getElementById('post-job-form').addEventListener('submit', async (e) => {
   184→        e.preventDefault();
   185→        const form = e.target;
   186→        const btn = form.querySelector('button[type="submit"]');
   187→        btn.disabled = true;
   188→        btn.textContent = 'Posting...';
   189→        
   190→        try {
   191→          const data = await apiCall('/jobs', {
   192→            method: 'POST',
   193→            body: JSON.stringify({
   194→              title: form.title.value,
   195→              company: form.company.value,
   196→              description: form.description.value,
   197→              requirements: form.requirements.value,
   198→              location: form.location.value,
   199→              salary_range: form.salary_range.value
   200→            })
   201→          });
   202→          
   203→          if (data?.success) {
   204→            closeModal();
   205→            loadJobs();
   206→            form.reset();
   207→          } else {
