  min-height: 100vh;
  padding: 140px 24px 80px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 80px;
  max-width: 1400px;
  margin: 0 auto;
}

.hero-content {
  flex: 1;
  max-width: 600px;
}

.hero-badge {
  display: inline-flex;
  padding: 8px 16px;
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-full);
  font-size: 14px;
  margin-bottom: 24px;
}

.hero h1 {
  font-family: var(--font-display);
  font-size: 64px;
  font-weight: 700;
  line-height: 1.1;
  margin-bottom: 24px;
}

.hero-subtitle {
  font-size: 20px;
  color: var(--text-secondary);
  margin-bottom: 40px;
}

.hero-cta {
  display: flex;
  gap: 16px;
  margin-bottom: 60px;
}

.hero-stats {
  display: flex;
  gap: 48px;
}

.stat {
  display: flex;
  flex-direction: column;
}

.stat-value {
  font-family: var(--font-display);
  font-size: 32px;
  font-weight: 700;
  color: var(--accent-primary);
}

.stat-label {
  font-size: 14px;
  color: var(--text-muted);
}

/* Hero Visual */
.hero-visual {
  flex: 1;
  max-width: 500px;
}

.interview-card {
