  font-size: 24px;
  font-weight: 600;
  margin-bottom: 8px;
}

.step-content p {
  font-size: 16px;
  color: var(--text-secondary);
}

/* Pricing Section */
.pricing {
  padding: 100px 24px;
  max-width: 900px;
  margin: 0 auto;
}

.pricing-cards {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 24px;
}

.pricing-card {
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 40px;
  position: relative;
}

.pricing-card.featured {
  border-color: var(--accent-primary);
  box-shadow: var(--shadow-glow);
}

.pricing-badge {
  position: absolute;
  top: -12px;
  left: 50%;
  transform: translateX(-50%);
  padding: 6px 16px;
  background: var(--accent-gradient);
  border-radius: var(--radius-full);
  font-size: 12px;
  font-weight: 600;
  color: #000;
}

.pricing-header {
  text-align: center;
  margin-bottom: 32px;
}

.pricing-header h3 {
  font-family: var(--font-display);
  font-size: 24px;
  margin-bottom: 12px;
}

.price {
  font-family: var(--font-display);
  font-size: 48px;
  font-weight: 700;
}

.price span {
  font-size: 16px;
  font-weight: 400;
  color: var(--text-muted);
}

.pricing-features {
  margin-bottom: 32px;
}

.pricing-features li {
  padding: 12px 0;
  border-bottom: 1px solid var(--border-color);
  font-size: 15px;
}

.pricing-features li.disabled {
  color: var(--text-muted);
}

/* CTA Section */
.cta {
  padding: 100px 24px;
  background: var(--bg-secondary);
  text-align: center;
}

.cta-content {
  max-width: 600px;
  margin: 0 auto;
}

.cta h2 {
  font-family: var(--font-display);
  font-size: 42px;
  font-weight: 700;
  margin-bottom: 16px;
}

.cta p {
  font-size: 18px;
  color: var(--text-secondary);
  margin-bottom: 32px;
}

/* Footer */
.footer {
  padding: 60px 24px 24px;
  border-top: 1px solid var(--border-color);
}

.footer-content {
  max-width: 1200px;
  margin: 0 auto;
  display: flex;
  justify-content: space-between;
  margin-bottom: 48px;
}

.footer-brand p {
  color: var(--text-muted);
  margin-top: 12px;
  font-size: 14px;
}

.footer-links {
  display: flex;
  gap: 80px;
}

.footer-col h4 {
  font-family: var(--font-display);
  font-size: 14px;
  font-weight: 600;
  margin-bottom: 16px;
  color: var(--text-muted);
}

.footer-col a {
  display: block;
  font-size: 14px;
  color: var(--text-secondary);
  padding: 6px 0;
  transition: color 0.2s;
}

.footer-col a:hover {
  color: var(--text-primary);
}

.footer-bottom {
  max-width: 1200px;
  margin: 0 auto;
  padding-top: 24px;
  border-top: 1px solid var(--border-color);
  font-size: 13px;
  color: var(--text-muted);
}

/* Responsive */
@media (max-width: 1024px) {
  .hero {
    flex-direction: column;
    text-align: center;
    padding-top: 120px;
  }

  .hero-cta {
    justify-content: center;
  }

  .hero-stats {
    justify-content: center;
  }

  .feature-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 768px) {
  .hero h1 {
    font-size: 42px;
  }

  .nav-links {
    display: none;
  }

  .feature-grid {
    grid-template-columns: 1fr;
  }

  .pricing-cards {
    grid-template-columns: 1fr;
  }

  .footer-content {
    flex-direction: column;
    gap: 40px;
  }

  .footer-links {
    gap: 40px;
  }
}

