    83→      <form id="post-job-form">
    84→        <div class="form-group">
    85→          <label>Job Title *</label>
    86→          <input type="text" name="title" required placeholder="e.g., Senior Product Manager">
    87→        </div>
    88→        <div class="form-group">
    89→          <label>Company</label>
    90→          <input type="text" name="company" placeholder="Company name">
    91→        </div>
    92→        <div class="form-group">
    93→          <label>Description</label>
    94→          <textarea name="description" rows="4" placeholder="Describe the role..."></textarea>
    95→        </div>
    96→        <div class="form-group">
    97→          <label>Requirements</label>
    98→          <textarea name="requirements" rows="3" placeholder="Key requirements..."></textarea>
    99→        </div>
   100→        <div class="form-row">
   101→          <div class="form-group">
   102→            <label>Location</label>
   103→            <input type="text" name="location" placeholder="e.g., Remote, NYC">
   104→          </div>
   105→          <div class="form-group">
