   118→  <script src="/js/main.js"></script>
   119→  <script>
   120→    let currentUser = null;
   121→    
   122→    document.addEventListener('DOMContentLoaded', async () => {
   123→      currentUser = await checkAuth();
   124→      if (!currentUser) {
   125→        window.location.href = '/login.html';
   126→        return;
   127→      }
   128→      
   129→      // Show post button for hiring managers
   130→      if (currentUser.role === 'hiring_manager' || currentUser.role === 'admin') {
   131→        document.getElementById('post-job-btn').style.display = 'flex';
   132→        document.getElementById('post-job-btn').onclick = () => openModal();
   133→      }
   134→      
   135→      loadJobs();
   136→      setupPostForm();
   137→    });
   138→    
   139→    async function loadJobs() {
   140→      try {
   141→        const data = await apiCall('/jobs');
   142→        const grid = document.getElementById('job-grid');
   143→        const emptyState = document.getElementById('empty-state');
   144→        
   145→        if (!data || data.jobs.length === 0) {
   146→          grid.style.display = 'none';
   147→          emptyState.style.display = 'block';
   148→          return;
   149→        }
   150→        
   151→        grid.innerHTML = data.jobs.map(job => `
   152→          <div class="job-card">
   153→            <div class="job-header">
   154→              <h3>${job.title}</h3>
   155→              <span class="job-type">${job.job_type || 'Full-time'}</span>
   156→            </div>
   157→            <div class="job-company">${job.company || job.poster_company || 'Company'}</div>
   158→            ${job.location ? `<div class="job-location">📍 ${job.location}</div>` : ''}
   159→            ${job.salary_range ? `<div class="job-salary">💰 ${job.salary_range}</div>` : ''}
   160→            ${job.description ? `<p class="job-desc">${job.description.substring(0, 150)}${job.description.length > 150 ? '...' : ''}</p>` : ''}
   161→            <div class="job-actions">
   162→              <a href="/interview.html?job_id=${job.id}&job_title=${encodeURIComponent(job.title)}&job_desc=${encodeURIComponent(job.description || '')}" class="btn btn-primary btn-sm">
   163→                Practice Interview
   164→              </a>
   165→            </div>
   166→          </div>
   167→        `).join('');
   168→        
   169→      } catch (err) {
   170→        console.error('Failed to load jobs:', err);
   171→      }
   172→    }
   173→    
   174→    function openModal() {
   175→      document.getElementById('post-job-modal').style.display = 'flex';
   176→    }
   177→    
   178→    function closeModal() {
   179→      document.getElementById('post-job-modal').style.display = 'none';
   180→    }
   181→    
   182→    function setupPostForm() {
   183→      document.getElementById('post-job-form').addEventListener('submit', async (e) => {
   184→        e.preventDefault();
   185→        const form = e.target;
   186→        const btn = form.querySelector('button[type="submit"]');
   187→        btn.disabled = true;
   188→        btn.textContent = 'Posting...';
   189→        
   190→        try {
   191→          const data = await apiCall('/jobs', {
   192→            method: 'POST',
   193→            body: JSON.stringify({
   194→              title: form.title.value,
   195→              company: form.company.value,
   196→              description: form.description.value,
   197→              requirements: form.requirements.value,
   198→              location: form.location.value,
   199→              salary_range: form.salary_range.value
   200→            })
   201→          });
   202→          
   203→          if (data?.success) {
   204→            closeModal();
   205→            loadJobs();
   206→            form.reset();
   207→          } else {
   208→            alert(data?.error || 'Failed to post job');
   209→          }
   210→        } catch (err) {
   211→          alert('Error posting job');
   212→        } finally {
   213→          btn.disabled = false;
   214→          btn.textContent = 'Post Job';
   215→        }
   216→      });
   217→    }
   218→  </script>
